var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"휴. 역시 쉽지 않은 상대로군.","JPN":"ふう、手こずらせやがって。","ENG":"Whew, you're as difficult as I thought.","TWN":"呼～果然是個麻煩人物！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"……그렇다고 숙녀를 이렇게 묶어 놓기야?","JPN":"……だからって、レディーをこんなふうに縛り付けていいの？","ENG":"Are you really going to keep a lady all tied up like this?","TWN":"……怎麼可以把淑女這樣五花大綁呢？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"간만에 얼굴 좀 보려고 센서 건드린 건데, 영 매너가 없네.","JPN":"久しぶりに顔でも見ようと思ってセンサーに触れてあげたのに、マナーがなってないわね。","ENG":"I touched your sensors on purpose because I wanted to see you. This is not nice.","TWN":"想說好久不見跟你打個招呼，才去碰感應器的，結果你真沒禮貌～"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다 같이 고생해서 받은 보상금 들고 도망친 인간에게 매너는 사치지.","JPN":"みんなで苦労して手に入れた報奨金を持ち逃げした人間に、マナーなんて不相応だろ。","ENG":"I don't have to be nice to someone who ran away with all my money.","TWN":"把大家辛苦賺到的獎金拿走，對你這種人還談什麼禮貌？！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"그건 어쩔 수 없었어. 이안의 뜻을 이루려면 돈이 상당히 많이 들거든.","JPN":"あれは仕方なかったのよ。イアンの遺志を継ぐためにはお金がかかるから。","ENG":"I had no choice. Carrying on Ian's legacy is costly.","TWN":"我也是有苦衷的，要完成伊恩的遺願，需要很大筆的錢。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"What?","TWN":"遺願……？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"나도 원래는 어릴 때부터 한결같은 과학도였어.","JPN":"アタシだって、元々は勤勉な科学者だったのよ。","ENG":"I've always been a scientist since I was young.","TWN":"我原本也是位科學家。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"사기꾼이 아니라?","JPN":"詐欺師じゃなくて？","ENG":"You mean, a swindler.","TWN":"不是金光黨嗎？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"어떻게 생각할지는 동생 자유지만.","JPN":"どう思うかは弟クンの自由だけど。","ENG":"You can think whatever you want.","TWN":"你要怎麼看我是你的自由，"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"이안이 리플레이서에 있을 때 했던 연구, 기억해?","JPN":"イアンがリプレイサー在籍中にしていた研究、覚えてる？","ENG":"But do you remember what Ian was studying at the Replacer Syndicate?","TWN":"不過你還記得伊恩在克隆集團時做的研究嗎？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That's...","TWN":"是……"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"<color=#ffd34c>특정 신호체계를 통해 침식체의 행동을 컨트롤하는 방법</color>……. 이었지.","JPN":"<color=#ffd34c>特定信号システムによって侵食体の行動をコントロールする方法</color>……だったな。","ENG":"<color=#ffd34c>How to manipulate C.O.s' behavior through a particular signal system</color>... If I remember correctly.","TWN":"<color=#ffd34c>透過特定信號系控制侵蝕體行為的方法</color>……這個嗎？"},"stage":{"bg":"MAINSTREAM_5100010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"맞아. 요즘은 공명파 발생기로 악용되는 정도지만…….","JPN":"そうよ。最近は共鳴波発生器で悪用される程度だけど……","ENG":"Correct. So far, it's only been used in that dangerous Resonance Pulse Generator, but...","TWN":"沒錯，雖然最近因為共鳴裝置的關係而遭到濫用……"},"stage":{"bg":"MAINSTREAM_5100010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"더 연구했다면 침식체들의 공격성을 억제하는 방법을 찾았을지도 몰라.","JPN":"もっと研究を進めていたら、侵食体の攻撃性を抑制する方法が見つかったかもしれない。","ENG":"If he had studied further, he could have found a way to suppress C.O.s' hostility.","TWN":"但只要繼續研究下去，或許可以找到抑制侵蝕體攻擊性的方法。"},"stage":{"bg":"MAINSTREAM_5100010","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"이안도, 나도, 리플레이서에 협력했던 연구자들은 결국 이면세계를 인류가 살 수 있는 세상으로 만들고 싶어했어.","JPN":"イアンもアタシも、リプレイサーに協力した研究者たちは、裏世界を人類が暮らせる世界にしたかったの。","ENG":"Ian and I and all the other researchers at the Replacer Syndicate only wanted to make the Counterside a livable place for humans.","TWN":"無論是伊恩或是我，甚至是幫助過克隆集團的其他研究員，我們最終都是希望打造一個人類可以在異界生存的世界。"},"stage":{"bg":"MAINSTREAM_5100010","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"그리고 내가 관여했던 건……. 엘릭서였고.","JPN":"そして私が関わっていたのは……エリクサーだった。","ENG":"And I was involved in... the Elixir.","TWN":"而我參與過的部分是……聖水。"},"stage":{"bg":"MAINSTREAM_5100010","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……그래. 리플레이서 사태 때 연구용 엘릭서를 겁도 없이 벌컥벌컥 들이마셨지.","JPN":"……ああ。リプレイサー事件の時、研究用のエリクサーを恐れげもなくがぶ飲みしてたな。","ENG":"Yes. You drank that test Elixir like water during the Replacer Incident.","TWN":"……嗯嗯，我有看過你在克隆集團事件時，牛飲研究用聖水的樣子。"},"stage":{"bg":"MAINSTREAM_5100010","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};